@Test public void handlesUnknownSelfClosingTags() {
    String h = "<custom /><unknown id='test' />content<regular>text</regular>";
    Document doc = Jsoup.parse(h);
    assertEquals("<custom /><unknown id=\"test\" />content<regular>text</regular>", TextUtil.stripNewlines(doc.body().html()));
}

@Test public void handlesKnownVoidElementsSelfClosing() {
    String h = "<img src='test.jpg' /><br /><input type='text' />";
    Document doc = Jsoup.parse(h);
    assertEquals("<img src=\"test.jpg\" /><br /><input type=\"text\" />", TextUtil.stripNewlines(doc.body().html()));
}

@Test public void handlesNestedKnownTagsSelfClosing() {
    String h = "<div><span /></div>";
    Document doc = Jsoup.parse(h);
    assertEquals("<div><span></span></div>", TextUtil.stripNewlines(doc.body().html()));
}
